const input = $input.first().json;

// Check if we got an error (404 = no games) or empty response
const isError = input.error || input.errorMessage || !input.data;

if (isError) {
  // No games found — send "no games" message
  return [{
    json: {
      discordBody: {
        embeds: [{
          title: '\u265f\ufe0f Chess Today',
          description: 'No games played today. Go play some chess!',
          color: 7506394,
          timestamp: new Date().toISOString()
        }]
      }
    }
  }];
}

const raw = input.data || input;

// Parse NDJSON (newline-delimited JSON)
let rawText = typeof raw === 'string' ? raw : JSON.stringify(raw);
let games = [];

try {
  const lines = rawText.split('\n').filter(l => l.trim());
  games = lines.map(line => JSON.parse(line));
} catch(e) {
  if (typeof raw === 'object' && !Array.isArray(raw)) {
    games = [raw];
  }
}

// Filter to today's games only
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();

const todayGames = games.filter(g => {
  const gameTime = g.createdAt || g.lastMoveAt || 0;
  return gameTime >= todayStart;
});

if (todayGames.length === 0) {
  return [{
    json: {
      discordBody: {
        embeds: [{
          title: '\u265f\ufe0f Chess Today',
          description: 'No games played today. Go play some chess!',
          color: 7506394,
          timestamp: new Date().toISOString()
        }]
      }
    }
  }];
}

// Calculate stats
const username = 'PASTE_YOUR_LICHESS_USERNAME_HERE';
const userLower = username.toLowerCase();
let wins = 0, losses = 0, draws = 0;
let ratingStart = null, ratingEnd = null;
const openings = {};
const timeControls = {};

for (const game of todayGames) {
  const isWhite = game.players?.white?.user?.id?.toLowerCase() === userLower ||
                  game.players?.white?.user?.name?.toLowerCase() === userLower;
  const playerColor = isWhite ? 'white' : 'black';
  const player = game.players?.[playerColor];
  const rating = player?.rating;

  if (ratingStart === null && rating) ratingStart = rating;
  if (rating) ratingEnd = rating;

  if (game.winner === playerColor) wins++;
  else if (game.winner) losses++;
  else if (game.status === 'draw' || game.status === 'stalemate') draws++;
  else losses++;

  const opening = game.opening?.name || 'Unknown';
  openings[opening] = (openings[opening] || 0) + 1;

  const speed = game.speed || 'unknown';
  timeControls[speed] = (timeControls[speed] || 0) + 1;
}

const topOpenings = Object.entries(openings)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, count]) => `${name} x${count}`)
  .join('\n');

const tcList = Object.entries(timeControls)
  .map(([tc, count]) => `${tc} x${count}`)
  .join(', ');

const ratingChange = (ratingStart && ratingEnd) ? ratingEnd - ratingStart : null;
const ratingStr = ratingChange !== null 
  ? (ratingChange >= 0 ? `+${ratingChange}` : `${ratingChange}`) 
  : 'N/A';

let color = 7506394;
if (wins > losses) color = 3066993;
else if (losses > wins) color = 15158332;

let description = `**Result:** ${wins}W / ${draws}D / ${losses}L`;
description += `\n**Rating change:** ${ratingStr}`;
if (ratingEnd) description += ` (current: ${ratingEnd})`;
description += `\n**Time controls:** ${tcList}`;
description += `\n\n**Openings:**\n${topOpenings}`;

return [{
  json: {
    discordBody: {
      embeds: [{
        title: `\u265f\ufe0f Chess Today \u2014 ${todayGames.length} game${todayGames.length === 1 ? '' : 's'} played`,
        description: description.substring(0, 2000),
        color: color,
        timestamp: new Date().toISOString()
      }]
    }
  }
}];
